generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc     "Motor current sensor measuring instantaneous motor current I_M of the permanent‑magnet synchronous motor."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc     "Motor shaft encoder measuring angular position r_M of the rotary joint."
    DTDFVocab:producedData MotorPositionAngleDataTransmitted
]

instance GearBoxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc     "Gear wheel encoder measuring angular position r_G positioned behind the cycloidal gearbox."
    DTDFVocab:producedData GearBoxPositionAngleDataTransmitted
]

instance OutputEncoderSensor : DTDFVocab:SensingComponent [
    base:desc     "Output (joint) angle encoder measuring angular position r_out of the rotary joint."
    DTDFVocab:producedData OutputPositionAngleDataTransmitted
]

// Derived physical data (calculated from primary sensors)
instance TorqueSensor : DTDFVocab:SensingComponent [
    base:desc     "Derived torque sensor calculating τ from current I_M and motor constants."
    DTDFVocab:producedData MotorTorqueDataTransmitted
]

instance AngularVelocitySensor : DTDFVocab:SensingComponent [
    base:desc     "Derived angular velocity sensor calculating ω from motor encoder angle r_M."
    DTDFVocab:producedData MotorAngularVelocityDataTransmitted
]

// C4: Data Transmitted
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPositionAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearBoxPositionAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearBoxEncoderSensor
]

instance OutputPositionAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom OutputEncoderSensor
]

instance MotorTorqueDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TorqueSensor
]

instance MotorAngularVelocityDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom AngularVelocitySensor
]

// C10: Models
instance AxisSysMLModel : DTDFVocab:Model [
    base:desc     "SysML BDD/IBD model of the first rotary axis of the MABI MAX 100 robot."
    DTDFVocab:inputTo SysMLModelingTool
]

instance MotorSysMLModel : DTDFVocab:Model [
    base:desc     "SysML BDD/IBD model of the permanent‑magnet synchronous motor."
    DTDFVocab:inputTo SysMLModelingTool
]

instance GearboxSysMLModel : DTDFVocab:Model [
    base:desc     "SysML BDD/IBD model of the cycloidal gearbox."
    DTDFVocab:inputTo SysMLModelingTool
]

instance IdealMotorSimulationModel : DTDFVocab:Model [
    base:desc     "Simulink model of the motor under ideal conditions without friction."
    DTDFVocab:inputTo SimulinkSimulator
]

instance FrictionMotorSimulationModel : DTDFVocab:Model [
    base:desc     "Simulink model of the motor including white‑box friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)."
    DTDFVocab:inputTo SimulinkSimulator
]

instance IdealGearboxSimulationModel : DTDFVocab:Model [
    base:desc     "Simulink model of the gearbox under ideal conditions without friction."
    DTDFVocab:inputTo SimulinkSimulator
]

instance FrictionGearboxSimulationModel : DTDFVocab:Model [
    base:desc     "Simulink model of the gearbox including white‑box friction models."
    DTDFVocab:inputTo SimulinkSimulator
]

// C10: Data instances
instance MotorCurrentData : DTDFVocab:Data [
    base:desc     "Measured motor current I_M stream."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo DataAggregationModule
]

instance MotorPositionAngleData : DTDFVocab:Data [
    base:desc     "Measured motor encoder angle r_M stream."
    DTDFVocab:fromData MotorPositionAngleDataTransmitted
    DTDFVocab:inputTo DataAggregationModule
]

instance GearBoxPositionAngleData : DTDFVocab:Data [
    base:desc     "Measured gear wheel encoder angle r_G stream."
    DTDFVocab:fromData GearBoxPositionAngleDataTransmitted
    DTDFVocab:inputTo DataAggregationModule
]

instance OutputPositionAngleData : DTDFVocab:Data [
    base:desc     "Measured output angle r_out stream."
    DTDFVocab:fromData OutputPositionAngleDataTransmitted
    DTDFVocab:inputTo DataAggregationModule
]

instance MotorTorqueData : DTDFVocab:Data [
    base:desc     "Derived torque τ stream calculated from I_M."
    DTDFVocab:fromData MotorTorqueDataTransmitted
    DTDFVocab:inputTo DataAggregationModule
]

instance MotorAngularVelocityData : DTDFVocab:Data [
    base:desc     "Derived angular velocity ω stream calculated from r_M."
    DTDFVocab:fromData MotorAngularVelocityDataTransmitted
    DTDFVocab:inputTo DataAggregationModule
]

instance SimulatedMotorPositionAngleData : DTDFVocab:Data [
    base:desc     "Simulated motor encoder angle r_M from friction‑included Simulink models."
    DTDFVocab:inputTo DataAggregationModule
]

instance SimulatedGearBoxPositionAngleData : DTDFVocab:Data [
    base:desc     "Simulated gear wheel encoder angle r_G from friction‑included Simulink models."
    DTDFVocab:inputTo DataAggregationModule
]

instance SimulatedOutputPositionAngleData : DTDFVocab:Data [
    base:desc     "Simulated output angle r_out from friction‑included Simulink models."
    DTDFVocab:inputTo DataAggregationModule
]

// C11: Enablers
instance SysMLModelingTool : DTDFVocab:Enabler [
    base:desc     "SysML modeling tool used to create BDD/IBD models of Axis, Motor, and Gearbox."
]

instance SimulinkSimulator : DTDFVocab:Enabler [
    base:desc     "MathWorks Simulink environment executing motor and gearbox simulation models."
]

instance MQTTBroker : DTDFVocab:Enabler [
    base:desc     "MQTT broker streaming live sensor data from the physical robot to the digital shadow."
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc     "Asset Administration Shell providing standardized asset description and data linking."
]

instance DashboardUI : DTDFVocab:Enabler [
    base:desc     "Unified dashboard UI for visualizing measured and simulated data traces."
]

instance DataAggregationModule : DTDFVocab:Enabler [
    base:desc     "Module aggregating, processing, and forwarding data to downstream services."
    DTDFVocab:enables UnifiedDashboardService, FrictionIdentificationService, RealTimeDataLinkingService, FrictionParameterGenerationService
]

instance FrictionModelProcessor : DTDFVocab:Enabler [
    base:desc     "Processing component consuming sensor data, applying friction models, and producing refined friction parameters."
]

// C6: Services
instance UnifiedDashboardService : DTDFVocab:Service [
    base:desc     "Service rendering a unified dashboard visualizing measured versus simulated data traces."
    DTDFVocab:provides SimulationDeviationVisualizationInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc     "Service performing continuous friction identification using white‑box and black‑box models."
    DTDFVocab:provides WearDetectionInsight, RefinedMotorFrictionParametersInsight, RefinedGearboxFrictionParametersInsight, MotionControlProfileInsight, SimulationDeviationVisualizationInsight
    DTDFVocab:provides GenerateMotionControlProfileAction, AdjustFrictionParametersAction
]

instance RealTimeDataLinkingService : DTDFVocab:Service [
    base:desc     "Service linking real‑time live data streams to the digital twin and aggregating data across components."
]

instance FrictionParameterGenerationService : DTDFVocab:Service [
    base:desc     "Service generating refined friction parameters to improve robot positioning accuracy."
    DTDFVocab:provides RefinedMotorFrictionParametersInsight, RefinedGearboxFrictionParametersInsight
]

// C17: Insights
instance RefinedMotorFrictionParametersInsight : DTDFVocab:Insight [
    base:desc     "Refined friction parameters derived for the permanent‑magnet synchronous motor."
]

instance RefinedGearboxFrictionParametersInsight : DTDFVocab:Insight [
    base:desc     "Refined friction parameters derived for the cycloidal gearbox."
]

instance WearDetectionInsight : DTDFVocab:Insight [
    base:desc     "Detection of wear or tool change effects on friction in the rotary joint."
]

instance MotionControlProfileInsight : DTDFVocab:Insight [
    base:desc     "Generation of improved motion control profiles to enhance positioning accuracy."
]

instance SimulationDeviationVisualizationInsight : DTDFVocab:Insight [
    base:desc     "Visualization of simulation‑measurement deviations for operator decision‑making."
]

// C17: Actions
instance GenerateMotionControlProfileAction : DTDFVocab:Action [
    base:desc     "Automated generation of refined motion control profiles based on identified friction dynamics."
    DTDFVocab:IsAutomatic true
]

instance AdjustFrictionParametersAction : DTDFVocab:Action [
    base:desc     "Optimum adjustment of friction parameters within simulation and control models."
    DTDFVocab:IsAutomatic false
]

// C5: Environment
instance IndustrialRobotEnvironment : DTDFVocab:Environment [
    base:contains FirstAxisSystem
]

// C3: Physical components
instance FirstAxisSystem : DTDFVocab:Component [
    base:desc     "First rotary axis of the MABI MAX 100 robot with 0–90° range and 75°/s speed, comprising a permanent‑magnet synchronous motor, low‑ratio cycloidal gearbox, and dual position encoders."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time, continuous (one‑way) data streaming and model updates synchronized with the robot’s operational cycle; the digital shadow processes live data during operation and feeds the updated friction models back into the motion controller"
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Digital shadow comprising engineering, simulation, and data‑calculation models linked via an AAS; data traces are collected from the PT sensors, processed by the processing component, and visualized in the dashboard; the constellation is orchestrated by a one‑way data flow from PT to DT, with all components deployed in a centralized environment"
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design (structural and dynamic modelling in SysML), Manufacture (implementation of hardware, AAS integration), Operation (continuous data acquisition, real‑time nominal and friction model identification, and ongoing calibration)"
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability of each data trace back to its source (sensor or model), validation of friction models against measured data, continuous identification and refinement of white‑box and black‑box friction parameters, use of simulation models with known motor constants, and uncertainty mitigation through combined modelling approaches"
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Digital shadow receives data from the PT via MQTT broker (one‑way publish/subscribe), with data payloads formatted as JSON or binary streams; no bidirectional control commands are sent back to the PT within this model"
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML, AAS, and MQTT standards for modeling, asset description, and data exchange"
]
